import{c as t,S as d,j as a,m as o}from"./chunks/framework.DvQr6YbT.js";const u=JSON.parse('{"title":"Core Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/index.md","filePath":"concepts/index.md","lastUpdated":1783497907000}'),s={name:"concepts/index.md"};function n(r,e,i,l,c,h){return d(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to “Core Concepts”">​</a></h1><p>Knowlery is easiest to understand as a review layer on top of your vault. Your notes are the source material. Skills are reusable prompts. Rules are the guardrails. The dashboard turns recent activity into a small set of actions, while Obsidian settings holds the deeper maintenance tools.</p><h2 id="one-core-three-shells" tabindex="-1">One Core, Three Shells <a class="header-anchor" href="#one-core-three-shells" aria-label="Permalink to “One Core, Three Shells”">​</a></h2><p>The same knowledge-base lifecycle is available in three shells over one workspace format:</p><table tabindex="0"><thead><tr><th>Shell</th><th>Gets you</th><th>Install</th></tr></thead><tbody><tr><td>Obsidian plugin</td><td>Everything: review space, Knowledge health UI, live in-app retrieval, plus all lifecycle operations</td><td>Community plugins</td></tr><tr><td><code>knowlery</code> CLI</td><td>The full lifecycle — <code>init</code> / <code>sync</code> / <code>health</code> / <code>query</code> / <code>stale</code> / <code>kb</code> / <code>bundle …</code> — for terminals, agents, and headless environments</td><td><code>npm i -g knowlery</code></td></tr><tr><td>MCP server</td><td><code>knowlery mcp</code> (stdio) and <code>knowlery mcp serve</code> (remote HTTP): tools, skills-as-prompts, and pages-as-resources for any MCP-capable agent</td><td>ships with the CLI</td></tr></tbody></table><p>A folder initialized by the CLI opens in Obsidian with zero migration, and any Knowlery vault works with the CLI as-is. All shells share one implementation of sync and migrations, and the workspace records which Knowlery version last synced it — an older shell refuses to sync rather than downgrade what a newer one upgraded. See <a href="./../guides/agents-mcp">Agents &amp; MCP</a> for the MCP surface.</p><h2 id="review-space" tabindex="-1">Review Space <a class="header-anchor" href="#review-space" aria-label="Permalink to “Review Space”">​</a></h2><p>Knowlery is not trying to replace your notes. It keeps a boundary between human-authored markdown and agent-maintained review material.</p><p>The dashboard is one action-first home:</p><table tabindex="0"><thead><tr><th>Section</th><th>Use</th></tr></thead><tbody><tr><td>Today&#39;s move</td><td>Start from the current activity context and choose a next move</td></tr><tr><td>Suggested moves</td><td>Pick a reusable review prompt without browsing raw skill files</td></tr><tr><td>Knowledge health</td><td>See compiled pages whose sources changed and notes never compiled, with a re-cook prompt</td></tr><tr><td>This note</td><td>Review the active Markdown note in context</td></tr><tr><td>Recent activity</td><td>Scan recent private activity receipts</td></tr><tr><td>This week</td><td>Generate and review a weekly summary</td></tr><tr><td>Bundles</td><td>Share reviewed knowledge bundles and manage installed ones</td></tr></tbody></table><p>Diagnostics, rules, schema shortcuts, platform switching, and the Skills library live under <strong>Settings -&gt; Knowlery</strong>.</p><h2 id="compiled-knowledge-layer" tabindex="-1">Compiled Knowledge Layer <a class="header-anchor" href="#compiled-knowledge-layer" aria-label="Permalink to “Compiled Knowledge Layer”">​</a></h2><p>The setup wizard creates four top-level knowledge directories:</p><table tabindex="0"><thead><tr><th>Directory</th><th>Type</th><th>Use</th></tr></thead><tbody><tr><td><code>entities/</code></td><td><code>entity</code></td><td>People, tools, organizations, projects, products, systems</td></tr><tr><td><code>concepts/</code></td><td><code>concept</code></td><td>Ideas, frameworks, theories, mental models</td></tr><tr><td><code>comparisons/</code></td><td><code>comparison</code></td><td>Side-by-side analysis of related things</td></tr><tr><td><code>queries/</code></td><td><code>query</code></td><td>Saved questions, investigations, and research threads</td></tr></tbody></table><p>These pages are meant to be readable by humans and predictable for agents. The shape is guided by <code>SCHEMA.md</code>, but health checks only enforce a minimum frontmatter core.</p><h2 id="knowledge-md" tabindex="-1"><code>KNOWLEDGE.md</code> <a class="header-anchor" href="#knowledge-md" aria-label="Permalink to “KNOWLEDGE.md”">​</a></h2><p><code>KNOWLEDGE.md</code> is the vault&#39;s operating guide. It tells agents:</p><ul><li>Which directories belong to the agent and which belong to the user.</li><li>How to retrieve knowledge with Obsidian-friendly commands.</li><li>Which skills are available.</li><li>How to cite vault sources with wikilinks.</li></ul><p>Agents should read it early when working in the vault.</p><h2 id="schema-md" tabindex="-1"><code>SCHEMA.md</code> <a class="header-anchor" href="#schema-md" aria-label="Permalink to “SCHEMA.md”">​</a></h2><p><code>SCHEMA.md</code> is a living convention file, not just a frontmatter template.</p><p>The current template groups guidance into:</p><ul><li>Knowledge Domains</li><li>Tag Taxonomy</li><li>Domain Taxonomy</li><li>Agent Page Conventions</li><li>Frontmatter Schema</li><li>Page Thresholds</li><li>Custom Fields</li></ul><p>It encourages fields like <code>title</code>, <code>date</code>, <code>created</code>, <code>updated</code>, <code>type</code>, <code>tags</code>, and <code>sources</code>, plus optional fields such as <code>status</code>, <code>domain</code>, <code>description</code>, <code>references</code>, and <code>author</code>.</p><p>Health diagnostics still use a smaller minimum check for knowledge pages:</p><table tabindex="0"><thead><tr><th>Type</th><th>Minimum fields</th></tr></thead><tbody><tr><td>Entity</td><td><code>type</code>, <code>created</code></td></tr><tr><td>Concept</td><td><code>type</code>, <code>created</code></td></tr><tr><td>Comparison</td><td><code>type</code>, <code>items</code>, <code>created</code></td></tr><tr><td>Query</td><td><code>type</code>, <code>status</code>, <code>created</code></td></tr></tbody></table><h2 id="index-base" tabindex="-1"><code>INDEX.base</code> <a class="header-anchor" href="#index-base" aria-label="Permalink to “INDEX.base”">​</a></h2><p><code>INDEX.base</code> is an Obsidian Bases index over the compiled knowledge layer.</p><p>It groups and sorts knowledge pages and exposes useful properties for humans browsing in Obsidian. Agents can still query it on demand with <code>obsidian base:query</code>, but candidate location for questions goes through the deterministic retrieval engine below.</p><h2 id="deterministic-retrieval" tabindex="-1">Deterministic Retrieval <a class="header-anchor" href="#deterministic-retrieval" aria-label="Permalink to “Deterministic Retrieval”">​</a></h2><p>Since 0.6.0, finding candidate pages for a question is one deterministic command with two transports running the same engine:</p><table tabindex="0"><thead><tr><th>Transport</th><th>When</th><th>Command</th></tr></thead><tbody><tr><td>In-app CLI</td><td>Obsidian running (1.12.2+, CLI enabled)</td><td><code>obsidian knowlery:query question=&quot;...&quot; [k=&lt;n&gt;] [json]</code></td></tr><tr><td>Headless script</td><td>Obsidian closed, plain Node</td><td><code>node .knowlery/bin/query.mjs &quot;...&quot; [--k &lt;n&gt;] [--json]</code></td></tr></tbody></table><p>The engine scans compiled pages, user notes, and installed bundles; scores with field weights (title/aliases over tags, description, then body); matches light word variants and Chinese phrases; credits a compiled page when a raw note it cites matches the question (so cross-language questions reach the compiled answer); and returns an explicit <code>No confident matches</code> verdict instead of noise.</p><p>The same machinery reports mechanical staleness:</p><ul><li><code>obsidian knowlery:stale</code> or <code>node .knowlery/bin/query.mjs --stale</code> lists compiled pages whose cited sources changed after the page was last written, user notes cited by no compiled page, and dangling <code>sources</code> references.</li><li>The dashboard&#39;s Knowledge health section shows the same report, and <code>/cook</code>&#39;s incremental mode uses it as its scope (<code>log.md</code> remains as append-only history).</li></ul><p>Retrieval quality is measured: the repository ships an evaluation harness (<code>evals/</code>) with a golden question set, a frozen baseline of the old retrieval flow, and CI checks that hold every change to at least the current scores.</p><h2 id="skills-and-suggested-moves" tabindex="-1">Skills and Suggested Moves <a class="header-anchor" href="#skills-and-suggested-moves" aria-label="Permalink to “Skills and Suggested Moves”">​</a></h2><p>Skills are markdown prompt packages installed in <code>.agents/skills/&lt;name&gt;/SKILL.md</code>.</p><p>The dashboard exposes natural-language moves first, and the settings tab exposes the source skills behind the scenes:</p><table tabindex="0"><thead><tr><th>Skill</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cook</code></td><td>Digest notes into knowledge pages and keep <code>SCHEMA.md</code> taxonomy in sync</td></tr><tr><td><code>ask</code></td><td>Answer questions against vault content</td></tr><tr><td><code>explore</code></td><td>Trace timelines and find connections</td></tr><tr><td><code>challenge</code></td><td>Pressure-test beliefs and detect drift</td></tr><tr><td><code>ideas</code></td><td>Generate actionable ideas from vault content</td></tr><tr><td><code>audit</code></td><td>Scan agent-maintained directories for structural health issues</td></tr><tr><td><code>organize</code></td><td>Suggest vault restructuring</td></tr><tr><td><code>obsidian-cli</code></td><td>Work with Obsidian through CLI patterns</td></tr><tr><td><code>obsidian-markdown</code></td><td>Write Obsidian-flavored markdown</td></tr><tr><td><code>obsidian-bases</code></td><td>Work with Obsidian Bases files</td></tr><tr><td><code>json-canvas</code></td><td>Create and edit JSON Canvas files</td></tr><tr><td><code>defuddle</code></td><td>Extract clean markdown from web pages</td></tr><tr><td><code>vault-conventions</code></td><td>Document and enforce vault naming conventions</td></tr></tbody></table><p>The Skills library can install registry skills, and skill detail views can copy example prompts, open the source file, or run a skill through the configured agent CLI.</p><h2 id="activity-ledger-and-weekly-summary" tabindex="-1">Activity Ledger and Weekly Summary <a class="header-anchor" href="#activity-ledger-and-weekly-summary" aria-label="Permalink to “Activity Ledger and Weekly Summary”">​</a></h2><p>Knowlery records lightweight private activity receipts in <code>.knowlery/activity/</code> when logging is enabled.</p><p>Those receipts feed:</p><ul><li>Today thread summaries and next moves.</li><li>This note suggestions.</li><li>Weekly summary reports in <code>.knowlery/reports/latest.html</code> and <code>.knowlery/reports/weekly/&lt;week-label&gt;.html</code>.</li><li>Optional daily review requests and results in <code>.knowlery/requests/</code> and <code>.knowlery/reviews/</code>.</li></ul><h2 id="freshness-review" tabindex="-1">Freshness Review <a class="header-anchor" href="#freshness-review" aria-label="Permalink to “Freshness Review”">​</a></h2><p>Freshness Review is local and approval-gated. Knowlery can collect candidate pages from <code>entities/</code>, <code>concepts/</code>, <code>comparisons/</code>, and <code>queries/</code>, prepare a request JSON file, and copy a prompt for an agent you run separately.</p><p>When you import the result JSON, Knowlery turns valid findings into suggestions. Applying a suggestion only patches scalar frontmatter fields such as <code>retrieval_priority</code>, <code>freshness_status</code>, <code>freshness_reviewed</code>, <code>superseded_by</code>, and <code>freshness_sidecar</code>. Evidence and previous frontmatter snapshots live in <code>.knowlery/freshness/notes/</code> sidecars so applied suggestions can be restored.</p><h2 id="knowledge-bundles" tabindex="-1">Knowledge Bundles <a class="header-anchor" href="#knowledge-bundles" aria-label="Permalink to “Knowledge Bundles”">​</a></h2><p>A knowledge bundle is a portable, reviewed slice of a vault&#39;s compiled knowledge, packaged in the OKF format.</p><p>On the sharing side, export scope is chosen from a seed topic plus its graph-closure, every item passes an approve/flag review gate with an automated risk scan, and the shipped <code>SCHEMA.md</code> is scoped to the taxonomy the bundle actually uses. On the receiving side, bundles install under <code>Library/&lt;bundle-id&gt;/</code>, are tracked in <code>.knowlery/bundles.json</code>, and stay read-only reference material until you fork a page into your own knowledge directories.</p><p>Installed bundles are part of retrieval: <code>KNOWLEDGE.md</code> gains a pointer block while bundles are installed, and the <code>/ask</code> skill reads each relevant bundle&#39;s <code>agent-index.json</code> alongside the vault&#39;s own compiled pages.</p><h2 id="platform-adapters" tabindex="-1">Platform Adapters <a class="header-anchor" href="#platform-adapters" aria-label="Permalink to “Platform Adapters”">​</a></h2><p>Knowlery supports two agent platforms:</p><table tabindex="0"><thead><tr><th>Platform</th><th>Config file</th><th>Rules directory</th></tr></thead><tbody><tr><td>Claude Code</td><td><code>.claude/CLAUDE.md</code></td><td><code>.claude/rules/</code></td></tr><tr><td>OpenCode</td><td><code>opencode.json</code></td><td><code>.agents/rules/</code></td></tr></tbody></table><p>Switching platforms regenerates the target platform config and can migrate rules from the previous platform directory.</p><h2 id="companion-chat" tabindex="-1">Companion Chat <a class="header-anchor" href="#companion-chat" aria-label="Permalink to “Companion Chat”">​</a></h2><p>Knowlery can send prompts to a companion chat UI when it is available:</p><ul><li>Claudian for Claude Code.</li><li><code>obsidian-agent-client</code> for OpenCode.</li></ul><p>That keeps review prompts inside the vault instead of pushing them into a separate app.</p><h2 id="vault-health" tabindex="-1">Vault Health <a class="header-anchor" href="#vault-health" aria-label="Permalink to “Vault Health”">​</a></h2><p>The diagnostics section in settings checks two things:</p><ul><li><strong>Content structure:</strong> note counts, wikilink counts, knowledge page counts, orphan notes, broken wikilinks, missing frontmatter.</li><li><strong>Configuration integrity:</strong> expected files, directories, rules, built-in skills, agent CLI detection, and platform config.</li></ul>',63)])])}const m=t(s,[["render",n]]);export{u as __pageData,m as default};
